from collections import deque
class Solution:
    def canReach(self, s, minJump, maxJump):
        n = len(s)
        if s[-1] != '0':
            return False
        # BFS with a pointer to avoid re-scanning already-queued indices
        visited = [False] * n
        visited[0] = True
        q = deque([0])
        far = 0  # highest index already enqueued/considered
        while q:
            i = q.popleft()
            lo = max(i + minJump, far + 1)
            hi = min(i + maxJump, n - 1)
            for j in range(lo, hi + 1):
                if s[j] == '0' and not visited[j]:
                    visited[j] = True
                    if j == n - 1:
                        return True
                    q.append(j)
            far = max(far, i + maxJump)
        return visited[n - 1]

