class Solution:
    def canReach(self, s, minJump, maxJump):
        n = len(s)
        if s[-1] != '0':
            return False
        reach = [0] * n
        reach[0] = 1
        pre = [0] * (n + 1)
        pre[1] = 1
        for i in range(1, n):
            if s[i] == '0':
                lo = max(0, i - maxJump)
                hi = i - minJump
                if hi >= lo:
                    if pre[hi + 1] - pre[lo] > 0:
                        reach[i] = 1
            pre[i + 1] = pre[i] + reach[i]
        return reach[n - 1] == 1

